     1→//! Shared keyword definitions for `#[light_account(...)]` attribute parsing.
     2→//!
     3→//! This module provides a single source of truth for valid keywords used in
     4→//! `#[light_account(...)]` attributes. Keywords use Anchor-style `namespace::key` syntax.
     5→//!
     6→//! ## Syntax
     7→//!
     8→//! All attribute parameters (except type markers) require a namespace prefix:
     9→//! - `token::seeds`, `token::mint`, `token::owner`, `token::bump`
    10→//! - `associated_token::authority`, `associated_token::mint`
    11→//! - `mint::signer`, `mint::authority`, `mint::decimals`, `mint::seeds`, etc.
    12→//!
    13→//! ## Example
    14→//!
    15→//! ```ignore
    16→//! #[light_account(init,
    17→//!     token::seeds = [VAULT_SEED, self.mint.key()],
    18→//!     token::mint = token_mint,
    19→//!     token::owner = vault_authority,
    20→//!     token::bump = params.vault_bump
    21→//! )]
    22→//! pub vault: UncheckedAccount<'info>,
    23→//! ```
    24→
    25→/// Valid keys for `pda::` namespace in `#[light_account(pda::...)]` attributes.
    26→/// Used by `#[derive(LightProgram)]` enum variants.
    27→/// - `seeds`: PDA seeds for account derivation
    28→/// - `zero_copy`: Flag indicating zero-copy deserialization
    29→pub const PDA_NAMESPACE_KEYS: &[&str] = &["seeds", "zero_copy"];
    30→
    31→/// Valid keys for `token::` namespace in `#[light_account(init, token::...)]` attributes.
    32→/// These map to the TokenAccountField struct.
    33→/// - `seeds`: Token account PDA seeds (for signing as the token account) - can be dynamic
    34→/// - `owner_seeds`: Owner PDA seeds (for signing when owner is a PDA) - MUST BE CONSTANTS ONLY
    35→pub const TOKEN_NAMESPACE_KEYS: &[&str] = &["seeds", "mint", "owner", "bump", "owner_seeds"];
    36→
    37→/// Valid keys for `associated_token::` namespace in `#[light_account(associated_token, ...)]`.
    38→/// Note: `authority` is the user-facing name (maps internally to `owner` in AtaField).
    39→pub const ASSOCIATED_TOKEN_NAMESPACE_KEYS: &[&str] = &["authority", "mint"];
    40→
    41→/// Valid keys for `mint::` namespace in `#[light_account(init, mint, ...)]` attributes.
    42→pub const MINT_NAMESPACE_KEYS: &[&str] = &[
    43→    "signer",
    44→    "authority",
    45→    "decimals",
    46→    "seeds",
    47→    "bump",
    48→    "freeze_authority",
    49→    "authority_seeds",
    50→    "authority_bump",
    51→    "name",
    52→    "symbol",
    53→    "uri",
    54→    "update_authority",
    55→    "additional_metadata",
    56→];
    57→
    58→/// Standalone keywords that don't require a value (flags).
    59→/// Only `init` can appear as a truly standalone keyword.
    60→/// `mint` and `zero_copy` are only valid after `init`.
    61→/// `token` and `associated_token` require namespaced syntax.
    62→pub const STANDALONE_KEYWORDS: &[&str] = &["init"];
    63→
    64→/// Keywords that support shorthand syntax within their namespace.
    65→/// For example, `token::mint` alone is equivalent to `token::mint = mint`.
    66→/// Maps namespace -> list of shorthand-eligible keys
    67→pub const SHORTHAND_KEYS_BY_NAMESPACE: &[(&str, &[&str])] = &[
    68→    ("token", &["mint", "owner", "bump"]), // seeds requires array, no shorthand
    69→    ("associated_token", &["authority", "mint"]),
    70→    // mint namespace does not support shorthand - values are typically expressions
    71→];
    72→
    73→/// Check if a keyword is a standalone flag (doesn't require a value).
    74→#[inline]
    75→pub fn is_standalone_keyword(keyword: &str) -> bool {
    76→    STANDALONE_KEYWORDS.contains(&keyword)
    77→}
    78→
    79→/// Check if a key supports shorthand syntax within a given namespace.
    80→/// Shorthand means the key can appear without `= value` and defaults to `key = key`.
    81→#[inline]
    82→pub fn is_shorthand_key(namespace: &str, key: &str) -> bool {
    83→    for (ns, keys) in SHORTHAND_KEYS_BY_NAMESPACE {
    84→        if *ns == namespace {
    85→            return keys.contains(&key);
    86→        }
    87→    }
    88→    false
    89→}
    90→
    91→/// Get the valid keys for a given namespace.
    92→///
    93→/// # Arguments
    94→/// * `namespace` - One of "token", "associated_token", or "mint"
    95→///
    96→/// # Returns
    97→/// A slice of valid key strings for the namespace.
    98→pub fn valid_keys_for_namespace(namespace: &str) -> &'static [&'static str] {
    99→    match namespace {
   100→        "pda" => PDA_NAMESPACE_KEYS,
   101→        "token" => TOKEN_NAMESPACE_KEYS,
   102→        "associated_token" => ASSOCIATED_TOKEN_NAMESPACE_KEYS,
   103→        "mint" => MINT_NAMESPACE_KEYS,
   104→        _ => &[],
   105→    }
   106→}
   107→
   108→/// Validate a key within a namespace.
   109→///
   110→/// # Arguments
   111→/// * `namespace` - The namespace (e.g., "token", "mint")
   112→/// * `key` - The key within that namespace
   113→///
   114→/// # Returns
   115→/// `Ok(())` if valid, `Err(error_message)` if invalid.
   116→pub fn validate_namespaced_key(namespace: &str, key: &str) -> Result<(), String> {
   117→    let valid_keys = valid_keys_for_namespace(namespace);
   118→
   119→    if valid_keys.is_empty() {
   120→        return Err(format!(
   121→            "Unknown namespace `{}`. Expected: pda, token, associated_token, or mint",
   122→            namespace
   123→        ));
   124→    }
   125→
   126→    if !valid_keys.contains(&key) {
   127→        return Err(format!(
   128→            "Unknown key `{}` in `{}::` namespace. Allowed: {}",
   129→            key,
   130→            namespace,
   131→            valid_keys.join(", ")
   132→        ));
   133→    }
   134→
   135→    Ok(())
   136→}
   137→
   138→/// Generate an error message for an unknown key within a namespace.
   139→///
   140→/// # Arguments
   141→/// * `namespace` - The namespace (e.g., "token", "mint")
   142→/// * `key` - The unknown key that was encountered
   143→///
   144→/// # Returns
   145→/// A formatted error message string.
   146→pub fn unknown_key_error(namespace: &str, key: &str) -> String {
   147→    let valid = valid_keys_for_namespace(namespace);
   148→    if valid.is_empty() {
   149→        format!(
   150→            "Unknown namespace `{}`. Expected: pda, token, associated_token, or mint",
   151→            namespace
   152→        )
   153→    } else {
   154→        format!(
   155→            "Unknown key `{}` in #[light_account({}, ...)]. Allowed for `{}::`: {}",
   156→            key,
   157→            namespace,
   158→            namespace,
   159→            valid.join(", ")
   160→        )
   161→    }
   162→}
   163→
   164→/// Generate an error message for a missing namespace prefix.
   165→///
   166→/// # Arguments
   167→/// * `key` - The key that's missing a namespace prefix
   168→/// * `account_type` - The account type context (e.g., "token", "mint")
   169→///
   170→/// # Returns
   171→/// A formatted error message string with suggestions.
   172→pub fn missing_namespace_error(key: &str, account_type: &str) -> String {
   173→    format!(
   174→        "Missing namespace prefix for `{}`. Use `{}::{}` instead of just `{}`",
   175→        key, account_type, key, key
   176→    )
   177→}
   178→
   179→#[cfg(test)]
   180→mod tests {
   181→    use super::*;
   182→
   183→    #[test]
   184→    fn test_pda_namespace_keys() {
   185→        assert!(PDA_NAMESPACE_KEYS.contains(&"seeds"));
   186→        assert!(PDA_NAMESPACE_KEYS.contains(&"zero_copy"));
   187→        assert!(!PDA_NAMESPACE_KEYS.contains(&"unknown"));
   188→    }
   189→
   190→    #[test]
   191→    fn test_token_namespace_keys() {
   192→        assert!(TOKEN_NAMESPACE_KEYS.contains(&"seeds"));
   193→        assert!(TOKEN_NAMESPACE_KEYS.contains(&"mint"));
   194→        assert!(TOKEN_NAMESPACE_KEYS.contains(&"owner"));
   195→        assert!(TOKEN_NAMESPACE_KEYS.contains(&"bump"));
   196→        assert!(!TOKEN_NAMESPACE_KEYS.contains(&"authority")); // use seeds for token PDA
   197→        assert!(!TOKEN_NAMESPACE_KEYS.contains(&"unknown"));
   198→    }
   199→
   200→    #[test]
   201→    fn test_associated_token_namespace_keys() {
   202→        assert!(ASSOCIATED_TOKEN_NAMESPACE_KEYS.contains(&"authority"));
   203→        assert!(ASSOCIATED_TOKEN_NAMESPACE_KEYS.contains(&"mint"));
   204→        assert!(!ASSOCIATED_TOKEN_NAMESPACE_KEYS.contains(&"bump")); // bump derived on-chain
   205→        assert!(!ASSOCIATED_TOKEN_NAMESPACE_KEYS.contains(&"owner")); // renamed to authority
   206→        assert!(!ASSOCIATED_TOKEN_NAMESPACE_KEYS.contains(&"unknown"));
   207→    }
   208→
   209→    #[test]
   210→    fn test_mint_namespace_keys() {
   211→        assert!(MINT_NAMESPACE_KEYS.contains(&"signer")); // renamed from mint_signer
   212→        assert!(MINT_NAMESPACE_KEYS.contains(&"authority"));
   213→        assert!(MINT_NAMESPACE_KEYS.contains(&"decimals"));
   214→        assert!(MINT_NAMESPACE_KEYS.contains(&"seeds")); // renamed from mint_seeds
   215→        assert!(MINT_NAMESPACE_KEYS.contains(&"bump")); // renamed from mint_bump
   216→        assert!(MINT_NAMESPACE_KEYS.contains(&"freeze_authority"));
   217→        assert!(MINT_NAMESPACE_KEYS.contains(&"authority_seeds"));
   218→        assert!(MINT_NAMESPACE_KEYS.contains(&"authority_bump"));
   219→        assert!(MINT_NAMESPACE_KEYS.contains(&"name"));
   220→        assert!(MINT_NAMESPACE_KEYS.contains(&"symbol"));
   221→        assert!(MINT_NAMESPACE_KEYS.contains(&"uri"));
   222→        assert!(MINT_NAMESPACE_KEYS.contains(&"update_authority"));
   223→        assert!(MINT_NAMESPACE_KEYS.contains(&"additional_metadata"));
   224→    }
   225→
   226→    #[test]
   227→    fn test_standalone_keywords() {
   228→        // Only init is a true standalone keyword
   229→        assert!(is_standalone_keyword("init"));
   230→        // mint and zero_copy are only valid after init, not standalone
   231→        assert!(!is_standalone_keyword("mint"));
   232→        assert!(!is_standalone_keyword("zero_copy"));
   233→        // token and associated_token require namespaced syntax
   234→        assert!(!is_standalone_keyword("token"));
   235→        assert!(!is_standalone_keyword("associated_token"));
   236→        assert!(!is_standalone_keyword("authority"));
   237→    }
   238→
   239→    #[test]
   240→    fn test_shorthand_keys() {
   241→        // token namespace
   242→        assert!(is_shorthand_key("token", "mint"));
   243→        assert!(is_shorthand_key("token", "owner"));
   244→        assert!(is_shorthand_key("token", "bump"));
   245→        assert!(!is_shorthand_key("token", "seeds")); // seeds requires array
   246→
   247→        // associated_token namespace
   248→        assert!(is_shorthand_key("associated_token", "authority"));
   249→        assert!(is_shorthand_key("associated_token", "mint"));
   250→
   251→        // mint namespace - no shorthand
   252→        assert!(!is_shorthand_key("mint", "signer"));
   253→        assert!(!is_shorthand_key("mint", "authority"));
   254→    }
   255→
   256→    #[test]
   257→    fn test_valid_keys_for_namespace() {
   258→        let pda_kw = valid_keys_for_namespace("pda");
   259→        assert_eq!(pda_kw, PDA_NAMESPACE_KEYS);
   260→
   261→        let token_kw = valid_keys_for_namespace("token");
   262→        assert_eq!(token_kw, TOKEN_NAMESPACE_KEYS);
   263→
   264→        let ata_kw = valid_keys_for_namespace("associated_token");
   265→        assert_eq!(ata_kw, ASSOCIATED_TOKEN_NAMESPACE_KEYS);
   266→
   267→        let mint_kw = valid_keys_for_namespace("mint");
   268→        assert_eq!(mint_kw, MINT_NAMESPACE_KEYS);
   269→
   270→        let unknown_kw = valid_keys_for_namespace("unknown");
   271→        assert!(unknown_kw.is_empty());
   272→    }
   273→
   274→    #[test]
   275→    fn test_validate_namespaced_key() {
   276→        // Valid keys
   277→        assert!(validate_namespaced_key("token", "seeds").is_ok());
   278→        assert!(validate_namespaced_key("token", "mint").is_ok());
   279→        assert!(validate_namespaced_key("associated_token", "authority").is_ok());
   280→        assert!(validate_namespaced_key("mint", "signer").is_ok());
   281→        assert!(validate_namespaced_key("mint", "decimals").is_ok());
   282→
   283→        // Invalid keys
   284→        assert!(validate_namespaced_key("token", "invalid").is_err());
   285→        assert!(validate_namespaced_key("token", "authority").is_err()); // use seeds for token
   286→        assert!(validate_namespaced_key("unknown_namespace", "key").is_err());
   287→    }
   288→
   289→    #[test]
   290→    fn test_unknown_key_error() {
   291→        let error = unknown_key_error("token", "invalid");
   292→        assert!(error.contains("invalid"));
   293→        assert!(error.contains("token"));
   294→        assert!(error.contains("seeds"));
   295→
   296→        let error = unknown_key_error("unknown", "key");
   297→        assert!(error.contains("Unknown namespace"));
   298→    }
   299→
   300→    #[test]
   301→    fn test_missing_namespace_error() {
   302→        let error = missing_namespace_error("authority", "token");
   303→        assert!(error.contains("token::authority"));
   304→        assert!(error.contains("Missing namespace prefix"));
   305→    }
   306→}
