     1→//! Unified #[light_account(...)] attribute parsing.
     2→//!
     3→//! This module provides a single unified syntax for all Light Protocol account types:
     4→//! - `#[light_account(init)]` - PDAs
     5→//! - `#[light_account(init, mint, ...)]` - Light Mints
     6→//! - `#[light_account(init, token::...)]` - Light token accounts
     7→//! - `#[light_account(init, associated_token::...)]` - Light ATAs
     8→//!
     9→//! ## Syntax (Anchor-style namespace::key)
    10→//!
    11→//! All parameters require a namespace prefix matching the account type.
    12→//! All light_account fields require `init` keyword.
    13→//!
    14→//! ### Token Account
    15→//! ```ignore
    16→//! #[light_account(init,
    17→//!     token::seeds = [VAULT_SEED, self.mint.key()],  // PDA seeds for signing
    18→//!     token::mint = token_mint,
    19→//!     token::owner = vault_authority,               // Owner account reference
    20→//!     token::bump = params.vault_bump               // Optional, auto-derived if omitted
    21→//! )]
    22→//! ```
    23→//!
    24→//! ### Associated Token Account
    25→//! ```ignore
    26→//! #[light_account(init,
    27→//!     associated_token::authority = owner,
    28→//!     associated_token::mint = mint,
    29→//! )]
    30→//! ```
    31→//!
    32→//! ### Mint
    33→//! ```ignore
    34→//! #[light_account(init, mint,
    35→//!     mint::signer = mint_signer,
    36→//!     mint::authority = authority,
    37→//!     mint::decimals = params.decimals,
    38→//!     mint::seeds = &[MINT_SIGNER_SEED, self.authority.key().as_ref()],
    39→//!     mint::bump = params.mint_signer_bump
    40→//! )]
    41→//! ```
    42→
    43→use syn::{
    44→    parse::{Parse, ParseStream},
    45→    Error, Expr, Field, Ident, Token, Type,
    46→};
    47→
    48→use super::mint::LightMintField;
    49→use crate::light_pdas::light_account_keywords::{
    50→    is_shorthand_key, is_standalone_keyword, missing_namespace_error, valid_keys_for_namespace,
    51→    validate_namespaced_key,
    52→};
    53→pub(super) use crate::light_pdas::seeds::extract_account_inner_type;
    54→
    55→// ============================================================================
    56→// Account Type Classification
    57→// ============================================================================
    58→
    59→/// Account type specifier parsed from the attribute.
    60→#[derive(Clone, Copy, Debug, PartialEq, Default)]
    61→pub enum LightAccountType {
    62→    #[default]
    63→    Pda, // Default (no type specifier) - for PDAs
    64→    Mint,            // `mint` keyword - for compressed mints
    65→    Token,           // `token` keyword - for token accounts
    66→    AssociatedToken, // `associated_token` keyword - for ATAs
    67→}
    68→
    69→impl LightAccountType {
    70→    /// Get the namespace string for this account type.
    71→    pub fn namespace(&self) -> &'static str {
    72→        match self {
    73→            LightAccountType::Pda => "pda",
    74→            LightAccountType::Mint => "mint",
    75→            LightAccountType::Token => "token",
    76→            LightAccountType::AssociatedToken => "associated_token",
    77→        }
    78→    }
    79→}
