    82→// Unified Parsed Result
    83→// ============================================================================
    84→
    85→/// Unified representation of a #[light_account(...)] field.
    86→#[derive(Debug)]
    87→pub enum LightAccountField {
    88→    Pda(Box<PdaField>),
    89→    Mint(Box<LightMintField>),
    90→    TokenAccount(Box<TokenAccountField>),
    91→    AssociatedToken(Box<AtaField>),
    92→}
    93→
    94→/// A field marked with #[light_account(init)] (PDA).
    95→#[derive(Debug)]
    96→pub struct PdaField {
    97→    pub ident: Ident,
    98→    pub address_tree_info: Expr,
    99→    pub output_tree: Expr,
   100→    /// True if the field is Box<Account<T>>, false if Account<T>
   101→    pub is_boxed: bool,
   102→    /// True if the field uses zero-copy serialization (AccountLoader)
   103→    pub is_zero_copy: bool,
   104→}
   105→
   106→/// A field marked with #[light_account(init, token::...)] (Token Account).
   107→#[derive(Clone, Debug)]
   108→pub struct TokenAccountField {
   109→    pub field_ident: Ident,
   110→    /// True if `init` keyword is present (generate creation code)
   111→    pub has_init: bool,
   112→    /// Token account PDA seeds for signing (from token::seeds = [...] parameter)
   113→    /// Used when the token account itself is a PDA that needs to sign for creation.
   114→    /// Note: Seeds should NOT include the bump - it's auto-derived or passed via `bump` parameter
   115→    pub seeds: Vec<Expr>,
   116→    /// Mint reference
   117→    pub mint: Option<Expr>,
   118→    /// Owner reference (the account that owns this token account)
   119→    pub owner: Option<Expr>,
   120→    /// Optional bump seed. If None, bump is auto-derived using find_program_address.
   121→    pub bump: Option<Expr>,
   122→}
   123→
   124→/// A field marked with #[light_account([init,] associated_token, ...)] (Associated Token Account).
   125→#[derive(Clone, Debug)]
   126→pub struct AtaField {
   127→    pub field_ident: Ident,
   128→    /// True if `init` keyword is present (generate creation code)
   129→    pub has_init: bool,
   130→    /// Owner of the ATA (from associated_token::authority = ... parameter)
   131→    /// Note: User-facing is "authority" but maps to internal "owner" field
   132→    pub owner: Expr,
   133→    /// Mint for the ATA (from associated_token::mint = ... parameter)
   134→    pub mint: Expr,
   135→}
   136→
   137→// ============================================================================
   138→// Custom Parser for #[light_account(init, [mint,] namespace::key = value, ...)]
   139→// ============================================================================
   140→
   141→/// Namespaced key-value pair in the attribute arguments.
   142→/// Syntax: `namespace::key = value` (e.g., `token::mint = token_mint`)
   143→struct NamespacedKeyValue {
   144→    namespace: Ident,
   145→    key: Ident,
   146→    value: Expr,
   147→}
   148→
   149→impl Parse for NamespacedKeyValue {
   150→    fn parse(input: ParseStream) -> syn::Result<Self> {
   151→        let namespace: Ident = input.parse()?;
   152→        input.parse::<Token![::]>()?;
   153→        let key: Ident = input.parse()?;
   154→
   155→        // Check for shorthand syntax (key alone without = value)
   156→        let value: Expr = if input.peek(Token![=]) {
   157→            input.parse::<Token![=]>()?;
   158→
   159→            // Handle bracketed content for authority and seeds arrays
   160→            if (key == "authority" || key == "seeds") && input.peek(syn::token::Bracket) {
   161→                let content;
   162→                syn::bracketed!(content in input);
   163→                let mut elements = Vec::new();
   164→                while !content.is_empty() {
   165→                    let elem: Expr = content.parse()?;
   166→                    elements.push(elem);
   167→                    if content.peek(Token![,]) {
   168→                        content.parse::<Token![,]>()?;
   169→                    }
   170→                }
   171→                syn::parse_quote!([#(#elements),*])
   172→            } else {
   173→                input.parse()?
   174→            }
   175→        } else {
   176→            // Shorthand: key alone means key = key
   177→            let namespace_str = namespace.to_string();
   178→            let key_str = key.to_string();
   179→            if is_shorthand_key(&namespace_str, &key_str) {
   180→                syn::parse_quote!(#key)
   181→            } else {
   182→                return Err(Error::new_spanned(
   183→                    &key,
   184→                    format!(
   185→                        "`{}::{}` requires a value (e.g., `{}::{} = ...`)",
   186→                        namespace_str, key_str, namespace_str, key_str
   187→                    ),
   188→                ));
   189→            }
   190→        };
   191→
   192→        Ok(Self {
   193→            namespace,
   194→            key,
   195→            value,
   196→        })
   197→    }
   198→}
   199→
   200→/// Parsed arguments from #[light_account(init, [mint,] ...)].
   201→struct LightAccountArgs {
   202→    /// True if `init` keyword is present (required for PDA/Mint, optional for Token/ATA).
   203→    has_init: bool,
   204→    /// True if `zero_copy` keyword is present (for AccountLoader fields using Pod serialization).
   205→    has_zero_copy: bool,
   206→    /// The account type (Pda, Mint, etc.).
   207→    account_type: LightAccountType,
   208→    /// Namespaced key-value pairs for additional arguments.
   209→    key_values: Vec<NamespacedKeyValue>,
   210→}
   211→
   212→/// Tracks seen standalone keywords to detect duplicates during parsing.
   213→#[derive(Default)]
   214→struct SeenKeywords {
   215→    init: Option<Ident>,
   216→    zero_copy: Option<Ident>,
   217→    account_type_keyword: Option<Ident>,
   218→}
   219→
   220→impl SeenKeywords {
   221→    /// Check and set the `init` keyword. Returns error if already seen.
   222→    fn set_init(&mut self, ident: &Ident) -> syn::Result<()> {
   223→        if self.init.is_some() {
   224→            return Err(Error::new_spanned(ident, "Duplicate `init` keyword"));
   225→        }
   226→        self.init = Some(ident.clone());
   227→        Ok(())
   228→    }
   229→
   230→    /// Check and set the `zero_copy` keyword. Returns error if already seen.
   231→    fn set_zero_copy(&mut self, ident: &Ident) -> syn::Result<()> {
   232→        if self.zero_copy.is_some() {
   233→            return Err(Error::new_spanned(ident, "Duplicate `zero_copy` keyword"));
   234→        }
   235→        self.zero_copy = Some(ident.clone());
   236→        Ok(())
   237→    }
   238→
   239→    /// Check and set an account type keyword (mint, token, associated_token).
   240→    /// Returns error if already seen (duplicate or conflicting type).
   241→    fn set_account_type(&mut self, ident: &Ident) -> syn::Result<()> {
   242→        if let Some(ref prev) = self.account_type_keyword {
   243→            let prev_name = prev.to_string();
   244→            let new_name = ident.to_string();
   245→            if prev_name == new_name {
   246→                return Err(Error::new_spanned(
   247→                    ident,
   248→                    format!("Duplicate `{}` keyword", new_name),
   249→                ));
   250→            } else {
   251→                return Err(Error::new_spanned(
   252→                    ident,
   253→                    format!(
   254→                        "Conflicting account type: `{}` was already specified, cannot also use `{}`",
   255→                        prev_name, new_name
   256→                    ),
   257→                ));
   258→            }
   259→        }
   260→        self.account_type_keyword = Some(ident.clone());
   261→        Ok(())
   262→    }
   263→}
   264→
   265→impl Parse for LightAccountArgs {
   266→    fn parse(input: ParseStream) -> syn::Result<Self> {
   267→        let mut seen = SeenKeywords::default();
   268→
   269→        // First token - either `init` or a namespace like `token::`
   270→        let first: Ident = input.parse()?;
   271→
   272→        // Handle mark-only mode: namespace-first syntax without init (e.g., `token::seeds = [...]`)
   273→        // This is allowed for token and associated_token fields - they skip code generation
   274→        if input.peek(Token![::]) {
   275→            let account_type = infer_type_from_namespace(&first)?;
   276→
   277→            // Only token and associated_token support mark-only mode
   278→            if account_type != LightAccountType::Token
   279→                && account_type != LightAccountType::AssociatedToken
   280→            {
   281→                return Err(Error::new_spanned(
   282→                    &first,
   283→                    format!(
   284→                        "#[light_account({}::...)] requires `init` keyword. \
   285→                         Use: #[light_account(init, {}::...)]",
   286→                        first, first
   287→                    ),
   288→                ));
   289→            }
   290→
   291→            // Parse the first key-value manually since we already consumed the namespace
   292→            input.parse::<Token![::]>()?;
   293→            let key: Ident = input.parse()?;
   294→            let namespace_str = first.to_string();
   295→            let key_str = key.to_string();
   296→
   297→            // Validate key is valid for this namespace
   298→            if let Err(err_msg) = validate_namespaced_key(&namespace_str, &key_str) {
   299→                return Err(Error::new_spanned(&key, err_msg));
   300→            }
   301→
   302→            // Parse value (handle shorthand and array syntax)
   303→            let value: Expr = if input.peek(Token![=]) {
   304→                input.parse::<Token![=]>()?;
   305→
   306→                // Handle bracketed content for authority and seeds arrays
   307→                if (key_str == "authority" || key_str == "seeds") && input.peek(syn::token::Bracket)
   308→                {
   309→                    let content;
   310→                    syn::bracketed!(content in input);
   311→                    let mut elements = Vec::new();
   312→                    while !content.is_empty() {
   313→                        let elem: Expr = content.parse()?;
   314→                        elements.push(elem);
   315→                        if content.peek(Token![,]) {
   316→                            content.parse::<Token![,]>()?;
   317→                        }
   318→                    }
   319→                    syn::parse_quote!([#(#elements),*])
   320→                } else {
   321→                    input.parse()?
   322→                }
   323→            } else {
   324→                // Shorthand: key alone means key = key
   325→                if is_shorthand_key(&namespace_str, &key_str) {
   326→                    syn::parse_quote!(#key)
   327→                } else {
   328→                    return Err(Error::new_spanned(
   329→                        &key,
   330→                        format!(
   331→                            "`{}::{}` requires a value (e.g., `{}::{} = ...`)",
   332→                            namespace_str, key_str, namespace_str, key_str
   333→                        ),
   334→                    ));
   335→                }
   336→            };
   337→
   338→            let first_kv = NamespacedKeyValue {
   339→                namespace: first,
   340→                key,
   341→                value,
   342→            };
   343→            let first_key = first_kv.key.to_string();
   344→            let mut key_values = vec![first_kv];
   345→
   346→            // Parse remaining key-values
   347→            let remaining = parse_namespaced_key_values(input, account_type, &[&first_key])?;
   348→            key_values.extend(remaining);
   349→
   350→            return Ok(Self {
   351→                has_init: false,
   352→                has_zero_copy: false,
   353→                account_type,
   354→                key_values,
   355→            });
   356→        }
   357→
   358→        if first != "init" {
   359→            return Err(Error::new_spanned(
   360→                &first,
   361→                "First argument to #[light_account] must be `init` or a namespaced key like `token::seeds`",
   362→            ));
   363→        }
   364→
   365→        seen.set_init(&first)?;
   366→
   367→        let mut account_type = LightAccountType::Pda;
   368→        let mut key_values = Vec::new();
   369→        let mut has_zero_copy = false;
   370→
   371→        // Parse remaining tokens
   372→        while !input.is_empty() {
   373→            input.parse::<Token![,]>()?;
   374→
   375→            if input.is_empty() {
   376→                break;
   377→            }
   378→
   379→            // Check if this is a namespaced key (has `::` after ident)
   380→            if input.peek(Ident) {
   381→                let lookahead = input.fork();
   382→                let ident: Ident = lookahead.parse()?;
   383→
   384→                // Check for init keyword (duplicate check)
   385→                if ident == "init" {
   386→                    let consumed: Ident = input.parse()?;
   387→                    seen.set_init(&consumed)?;
   388→                    continue;
   389→                }
   390→
   391→                // Check for zero_copy keyword (standalone flag)
   392→                if ident == "zero_copy" {
   393→                    let consumed: Ident = input.parse()?;
   394→                    seen.set_zero_copy(&consumed)?;
   395→                    has_zero_copy = true;
   396→                    continue;
   397→                }
   398→
   399→                // If followed by `::`, infer type from namespace
   400→                if lookahead.peek(Token![::]) {
   401→                    // Infer account type from namespace
   402→                    let inferred_type = infer_type_from_namespace(&ident)?;
   403→
   404→                    // Check for duplicate/conflicting account type
   405→                    if account_type != LightAccountType::Pda {
   406→                        seen.set_account_type(&ident)?; // Will error on conflict
   407→                    } else {
   408→                        seen.set_account_type(&ident)?;
   409→                        account_type = inferred_type;
   410→                    }
   411→
   412→                    // Parse this key-value and remaining ones
   413→                    let kv: NamespacedKeyValue = input.parse()?;
   414→                    key_values.push(kv);
   415→
   416→                    // Parse remaining key-values, passing the first key as already-seen
   417→                    let first_key = key_values
   418→                        .last()
   419→                        .map(|kv| kv.key.to_string())
   420→                        .unwrap_or_default();
   421→                    let remaining =
   422→                        parse_namespaced_key_values(input, account_type, &[&first_key])?;
   423→                    key_values.extend(remaining);
   424→                    break;
   425→                }
   426→
   427→                // Check for explicit mint type keyword (token/associated_token require namespaced syntax)
   428→                if ident == "mint" {
   429→                    let consumed: Ident = input.parse()?;
   430→                    seen.set_account_type(&consumed)?;
   431→                    account_type = LightAccountType::Mint;
   432→                    key_values = parse_namespaced_key_values(input, account_type, &[])?;
   433→                    break;
   434→                }
   435→
   436→                // Standalone token/associated_token keywords are not allowed - must use namespaced syntax
   437→                if ident == "token" || ident == "associated_token" {
   438→                    return Err(Error::new_spanned(
   439→                        &ident,
   440→                        format!(
   441→                            "Standalone `{}` keyword is not allowed. Use namespaced syntax: `{}::seeds = [...]`",
   442→                            ident, ident
   443→                        ),
   444→                    ));
   445→                }
   446→
   447→                // Old syntax - give helpful error
   448→                return Err(Error::new_spanned(
   449→                    &ident,
   450→                    format!(
   451→                        "Unknown keyword `{}`. Use namespaced syntax like `token::seeds` or `mint::signer`",
   452→                        ident
   453→                    ),
   454→                ));
   455→            }
   456→        }
   457→
   458→        Ok(Self {
   459→            has_init: true,
   460→            has_zero_copy,
   461→            account_type,
   462→            key_values,
   463→        })
   464→    }
   465→}
   466→
   467→/// Infer account type from namespace identifier.
   468→fn infer_type_from_namespace(namespace: &Ident) -> Result<LightAccountType, syn::Error> {
   469→    let ns = namespace.to_string();
   470→    match ns.as_str() {
   471→        "token" => Ok(LightAccountType::Token),
   472→        "associated_token" => Ok(LightAccountType::AssociatedToken),
   473→        "mint" => Ok(LightAccountType::Mint),
   474→        _ => Err(Error::new_spanned(
   475→            namespace,
   476→            format!(
   477→                "Unknown namespace `{}`. Expected: token, associated_token, or mint",
   478→                ns
   479→            ),
   480→        )),
   481→    }
   482→}
   483→
   484→/// Parse namespaced key-value pairs for token, associated_token, and mint attributes.
   485→/// Syntax: `namespace::key = value` (e.g., `token::mint = token_mint`)
   486→///
   487→/// `already_seen` contains keys that were already parsed before calling this function
   488→/// (e.g., the first key in namespaced-first syntax like `#[light_account(init, token::seeds = ...)]`).
   489→fn parse_namespaced_key_values(
   490→    input: ParseStream,
   491→    account_type: LightAccountType,
   492→    already_seen: &[&str],
   493→) -> syn::Result<Vec<NamespacedKeyValue>> {
   494→    let mut key_values = Vec::new();
   495→    let mut seen_keys: std::collections::HashSet<String> =
   496→        already_seen.iter().map(|s| s.to_string()).collect();
   497→    let expected_namespace = account_type.namespace();
   498→
   499→    while !input.is_empty() {
   500→        input.parse::<Token![,]>()?;
   501→
   502→        if input.is_empty() {
   503→            break;
   504→        }
   505→
   506→        // Check if this looks like an old-style non-namespaced key
   507→        let fork = input.fork();
   508→        let maybe_key: Ident = fork.parse()?;
   509→
   510→        // If followed by `=` but not `::`, it's old syntax
   511→        if fork.peek(Token![=]) && !input.peek2(Token![::]) {
   512→            // Check if this is just a standalone keyword
   513→            if !is_standalone_keyword(&maybe_key.to_string()) {
   514→                return Err(Error::new_spanned(
   515→                    &maybe_key,
   516→                    missing_namespace_error(&maybe_key.to_string(), expected_namespace),
   517→                ));
   518→            }
   519→        }
   520→
   521→        let kv: NamespacedKeyValue = input.parse()?;
   522→
   523→        let namespace_str = kv.namespace.to_string();
   524→        let key_str = kv.key.to_string();
   525→
   526→        // Validate namespace matches account type
   527→        if namespace_str != expected_namespace {
   528→            return Err(Error::new_spanned(
   529→                &kv.namespace,
   530→                format!(
   531→                    "Namespace `{}` doesn't match account type `{}`. Use `{}::{}` instead.",
   532→                    namespace_str, expected_namespace, expected_namespace, key_str
   533→                ),
   534→            ));
   535→        }
   536→
   537→        // Check for duplicate keys
   538→        if !seen_keys.insert(key_str.clone()) {
   539→            return Err(Error::new_spanned(
   540→                &kv.key,
   541→                format!(
   542→                    "Duplicate key `{}::{}` in #[light_account({}, ...)]. Each key can only appear once.",
   543→                    namespace_str,
   544→                    key_str,
   545→                    expected_namespace
   546→                ),
   547→            ));
   548→        }
   549→
   550→        // Validate key is valid for this namespace
   551→        if let Err(err_msg) = validate_namespaced_key(&namespace_str, &key_str) {
   552→            return Err(Error::new_spanned(&kv.key, err_msg));
   553→        }
   554→
   555→        key_values.push(kv);
   556→    }
   557→
   558→    Ok(key_values)
   559→}
   560→
   561→// ============================================================================
   562→// Main Parsing Function
   563→// ============================================================================
   564→
   565→/// Parse #[light_account(...)] attribute from a field.
   566→/// Returns None if no light_account attribute or if it's a mark-only token/ata field.
   567→/// Returns Some(LightAccountField) for PDA, Mint, or init Token/Ata fields.
   568→///
   569→/// # Arguments
   570→/// * `field` - The field to parse
   571→/// * `field_ident` - The field identifier
   572→/// * `direct_proof_arg` - If `Some`, CreateAccountsProof is passed directly as an instruction arg
   573→///   with this name, so defaults should use `<name>.field` instead of `params.create_accounts_proof.field`
   574→pub(crate) fn parse_light_account_attr(
   575→    field: &Field,
   576→    field_ident: &Ident,
   577→    direct_proof_arg: &Option<Ident>,
   578→) -> Result<Option<LightAccountField>, syn::Error> {
   579→    for attr in &field.attrs {
   580→        if attr.path().is_ident("light_account") {
   581→            let args: LightAccountArgs = attr.parse_args()?;
   582→
   583→            // Mark-only mode: token/ata without init
   584→            // - Still generates TokenAccountField/AtaField with has_init = false
   585→            // - Seeds structs and variant enums are generated for decompression
   586→            // - LightPreInit skips the CPI call (user handles it manually)
   587→            // Note: Validation for mark-only mode is handled in build_token_account_field
   588→
   589→            // For PDA and Mint, init is required
   590→            if !args.has_init
   591→                && (args.account_type == LightAccountType::Pda
   592→                    || args.account_type == LightAccountType::Mint)
   593→            {
   594→                return Err(Error::new_spanned(
   595→                    attr,
   596→                    "#[light_account] requires `init` as the first argument for PDA/Mint",
   597→                ));
   598→            }
   599→
   600→            return match args.account_type {
   601→                LightAccountType::Pda => {
   602→                    Ok(Some(LightAccountField::Pda(Box::new(build_pda_field(
   603→                        field,
   604→                        field_ident,
   605→                        &args.key_values,
   606→                        direct_proof_arg,
   607→                        args.has_zero_copy,
   608→                    )?))))
   609→                }
   610→                LightAccountType::Mint => Ok(Some(LightAccountField::Mint(Box::new(
   611→                    build_mint_field(field_ident, &args.key_values, attr)?,
   612→                )))),
   613→                LightAccountType::Token => Ok(Some(LightAccountField::TokenAccount(Box::new(
   614→                    build_token_account_field(field_ident, &args.key_values, args.has_init, attr)?,
   615→                )))),
   616→                LightAccountType::AssociatedToken => {
   617→                    Ok(Some(LightAccountField::AssociatedToken(Box::new(
   618→                        build_ata_field(field_ident, &args.key_values, args.has_init, attr)?,
   619→                    ))))
   620→                }
   621→            };
   622→        }
   623→    }
   624→    Ok(None)
   625→}
   626→
   627→/// Check if a type is AccountLoader<'info, T>
   628→fn is_account_loader_type(ty: &Type) -> bool {
   629→    if let Type::Path(type_path) = ty {
   630→        return type_path
   631→            .path
   632→            .segments
   633→            .iter()
   634→            .any(|seg| seg.ident == "AccountLoader");
   635→    }
   636→    false
   637→}
   638→
   639→/// Build a PdaField from parsed key-value pairs.
   640→///
   641→/// # Arguments
   642→/// * `direct_proof_arg` - If `Some`, use `<name>.field` for defaults instead of `params.create_accounts_proof.field`
   643→/// * `has_zero_copy` - True if `zero_copy` keyword was present in the attribute
   644→fn build_pda_field(
   645→    field: &Field,
   646→    field_ident: &Ident,
   647→    key_values: &[NamespacedKeyValue],
   648→    direct_proof_arg: &Option<Ident>,
   649→    has_zero_copy: bool,
   650→) -> Result<PdaField, syn::Error> {
   651→    // Reject any key-value pairs - PDA only needs `init`
   652→    // Tree info is always auto-fetched from CreateAccountsProof
   653→    if !key_values.is_empty() {
   654→        let keys: Vec<_> = key_values
   655→            .iter()
   656→            .map(|kv| format!("{}::{}", kv.namespace, kv.key))
   657→            .collect();
   658→        return Err(Error::new_spanned(
   659→            &key_values[0].key,
   660→            format!(
   661→                "Unexpected arguments for PDA: {}. \
   662→                 #[light_account(init)] takes no additional arguments. \
   663→                 address_tree_info and output_tree are automatically sourced from CreateAccountsProof.",
   664→                keys.join(", ")
   665→            ),
   666→        ));
   667→    }
   668→
   669→    // Always fetch from CreateAccountsProof
   670→    // TODO: This assumes `params.create_accounts_proof` exists in the instruction parameters.
   671→    // Currently there's no compile-time validation that the instruction actually has this field.
   672→    // A future improvement could:
   673→    // 1. Parse the instruction's params struct to verify the field exists
   674→    // 2. Provide a clearer error at macro expansion time if missing
   675→    // 3. Support alternative field names via attribute syntax
   676→    let (address_tree_info, output_tree) = if let Some(proof_ident) = direct_proof_arg {
   677→        (
   678→            syn::parse_quote!(#proof_ident.address_tree_info),
   679→            syn::parse_quote!(#proof_ident.output_state_tree_index),
   680→        )
   681→    } else {
   682→        (
   683→            syn::parse_quote!(params.create_accounts_proof.address_tree_info),
   684→            syn::parse_quote!(params.create_accounts_proof.output_state_tree_index),
   685→        )
   686→    };
   687→
   688→    // Detect if field type is AccountLoader
   689→    let is_account_loader = is_account_loader_type(&field.ty);
   690→
   691→    // Validate AccountLoader requires zero_copy
   692→    if is_account_loader && !has_zero_copy {
   693→        return Err(Error::new_spanned(
   694→            &field.ty,
   695→            "AccountLoader fields require #[light_account(init, zero_copy)]. \
   696→             AccountLoader uses zero-copy (Pod) serialization which is incompatible \
   697→             with the default Borsh decompression path.",
   698→        ));
   699→    }
   700→
   701→    // Validate non-AccountLoader forbids zero_copy
   702→    if !is_account_loader && has_zero_copy {
   703→        return Err(Error::new_spanned(
   704→            &field.ty,
   705→            "zero_copy can only be used with AccountLoader fields. \
   706→             For Account<'info, T> fields, remove the zero_copy keyword.",
   707→        ));
   708→    }
   709→
   710→    // Validate this is an Account type (or Box<Account>) or AccountLoader
   711→    let (is_boxed, _inner_type) =
   712→        extract_account_inner_type(&field.ty).map_err(|e| e.into_syn_error(&field.ty))?;
   713→
   714→    Ok(PdaField {
   715→        ident: field_ident.clone(),
   716→        address_tree_info,
   717→        output_tree,
   718→        is_boxed,
   719→        is_zero_copy: has_zero_copy,
   720→    })
   721→}
   722→
   723→/// Build a LightMintField from parsed namespaced key-value pairs.
   724→///
   725→/// Mapping from new syntax to internal fields:
   726→/// - `mint::signer` -> `mint_signer`
   727→/// - `mint::authority` -> `authority`
   728→/// - `mint::decimals` -> `decimals`
   729→/// - `mint::seeds` -> `mint_seeds`
   730→/// - `mint::bump` -> `mint_bump`
   731→/// - `mint::freeze_authority` -> `freeze_authority`
   732→/// - `mint::authority_seeds` -> `authority_seeds`
   733→/// - `mint::authority_bump` -> `authority_bump`
   734→/// - `mint::name` -> `name`
   735→/// - `mint::symbol` -> `symbol`
   736→/// - `mint::uri` -> `uri`
   737→/// - `mint::update_authority` -> `update_authority`
   738→/// - `mint::additional_metadata` -> `additional_metadata`
   739→fn build_mint_field(
   740→    field_ident: &Ident,
   741→    key_values: &[NamespacedKeyValue],
   742→    attr: &syn::Attribute,
   743→) -> Result<LightMintField, syn::Error> {
   744→    // Required fields
   745→    let mut mint_signer: Option<Expr> = None;
   746→    let mut authority: Option<Expr> = None;
   747→    let mut decimals: Option<Expr> = None;
   748→    let mut mint_seeds: Option<Expr> = None;
   749→
   750→    // Optional fields
   751→    let mut freeze_authority: Option<Ident> = None;
   752→    let mut authority_seeds: Option<Expr> = None;
   753→    let mut mint_bump: Option<Expr> = None;
   754→    let mut authority_bump: Option<Expr> = None;
   755→
   756→    // Metadata fields
   757→    let mut name: Option<Expr> = None;
   758→    let mut symbol: Option<Expr> = None;
   759→    let mut uri: Option<Expr> = None;
   760→    let mut update_authority: Option<Ident> = None;
   761→    let mut additional_metadata: Option<Expr> = None;
   762→
   763→    for kv in key_values {
   764→        match kv.key.to_string().as_str() {
   765→            // Required fields (new names)
   766→            "signer" => mint_signer = Some(kv.value.clone()),
   767→            "authority" => authority = Some(kv.value.clone()),
   768→            "decimals" => decimals = Some(kv.value.clone()),
   769→            "seeds" => mint_seeds = Some(kv.value.clone()),
   770→
   771→            // Optional fields
   772→            "bump" => mint_bump = Some(kv.value.clone()),
   773→            "freeze_authority" => {
   774→                freeze_authority = Some(expr_to_ident(&kv.value, "mint::freeze_authority")?);
   775→            }
   776→            "authority_seeds" => authority_seeds = Some(kv.value.clone()),
   777→            "authority_bump" => authority_bump = Some(kv.value.clone()),
   778→
   779→            // Metadata fields
   780→            "name" => name = Some(kv.value.clone()),
   781→            "symbol" => symbol = Some(kv.value.clone()),
   782→            "uri" => uri = Some(kv.value.clone()),
   783→            "update_authority" => {
   784→                update_authority = Some(expr_to_ident(&kv.value, "mint::update_authority")?);
   785→            }
   786→            "additional_metadata" => additional_metadata = Some(kv.value.clone()),
   787→
   788→            other => {
   789→                return Err(Error::new_spanned(
   790→                    &kv.key,
   791→                    format!(
   792→                        "Unknown key `mint::{}`. Allowed: {}",
   793→                        other,
   794→                        valid_keys_for_namespace("mint").join(", ")
   795→                    ),
   796→                ));
   797→            }
   798→        }
   799→    }
   800→
   801→    // Validate required fields
   802→    let mint_signer = mint_signer.ok_or_else(|| {
   803→        Error::new_spanned(
   804→            attr,
   805→            "#[light_account(init, mint, ...)] requires `mint::signer`",
   806→        )
   807→    })?;
   808→    let authority = authority.ok_or_else(|| {
   809→        Error::new_spanned(
   810→            attr,
   811→            "#[light_account(init, mint, ...)] requires `mint::authority`",
   812→        )
   813→    })?;
   814→    let decimals = decimals.ok_or_else(|| {
   815→        Error::new_spanned(
   816→            attr,
   817→            "#[light_account(init, mint, ...)] requires `mint::decimals`",
   818→        )
   819→    })?;
   820→    let mint_seeds = mint_seeds.ok_or_else(|| {
   821→        Error::new_spanned(
   822→            attr,
   823→            "#[light_account(init, mint, ...)] requires `mint::seeds`",
   824→        )
   825→    })?;
   826→
   827→    // Validate metadata fields (all-or-nothing rule)
   828→    validate_metadata_fields(
   829→        &name,
   830→        &symbol,
   831→        &uri,
   832→        &update_authority,
   833→        &additional_metadata,
   834→        attr,
   835→    )?;
   836→
   837→    Ok(LightMintField {
   838→        field_ident: field_ident.clone(),
   839→        mint_signer,
   840→        authority,
   841→        decimals,
   842→        freeze_authority,
   843→        mint_seeds,
   844→        mint_bump,
   845→        authority_seeds,
   846→        authority_bump,
   847→        name,
   848→        symbol,
   849→        uri,
   850→        update_authority,
   851→        additional_metadata,
   852→    })
   853→}
