   855→/// Build a TokenAccountField from parsed namespaced key-value pairs.
   856→///
   857→/// Mapping from new syntax to internal fields:
   858→/// - `token::seeds` -> `seeds` (token account PDA seeds for signing)
   859→/// - `token::mint` -> `mint`
   860→/// - `token::owner` -> `owner`
   861→/// - `token::bump` -> `bump`
   862→fn build_token_account_field(
   863→    field_ident: &Ident,
   864→    key_values: &[NamespacedKeyValue],
   865→    has_init: bool,
   866→    attr: &syn::Attribute,
   867→) -> Result<TokenAccountField, syn::Error> {
   868→    let mut seeds: Option<Expr> = None;
   869→    let mut mint: Option<Expr> = None;
   870→    let mut owner: Option<Expr> = None;
   871→    let mut bump: Option<Expr> = None;
   872→
   873→    for kv in key_values {
   874→        match kv.key.to_string().as_str() {
   875→            "seeds" => seeds = Some(kv.value.clone()),
   876→            "mint" => mint = Some(kv.value.clone()),
   877→            "owner" => owner = Some(kv.value.clone()),
   878→            "bump" => bump = Some(kv.value.clone()),
   879→            // owner_seeds is parsed but not stored (used by #[light_program] only)
   880→            "owner_seeds" => {
   881→                if let Expr::Array(_) = &kv.value {
   882→                    // Valid syntax, but not used by #[derive(LightAccounts)]
   883→                } else {
   884→                    return Err(Error::new_spanned(
   885→                        &kv.value,
   886→                        "token::owner_seeds must be an array, e.g., [b\"seed\", CONSTANT.as_bytes()]",
   887→                    ));
   888→                }
   889→            }
   890→            other => {
   891→                return Err(Error::new_spanned(
   892→                    &kv.key,
   893→                    format!(
   894→                        "Unknown key `token::{}`. Expected: seeds, mint, owner, bump, owner_seeds",
   895→                        other
   896→                    ),
   897→                ));
   898→            }
   899→        }
   900→    }
   901→
   902→    // Track if owner_seeds was provided (for mark-only validation)
   903→    let has_owner_seeds = key_values.iter().any(|kv| kv.key == "owner_seeds");
   904→
   905→    // Validation depends on init vs mark-only mode
   906→    if has_init {
   907→        // Init mode: requires seeds, mint, and owner
   908→        if seeds.is_none() {
   909→            return Err(Error::new_spanned(
   910→                attr,
   911→                "#[light_account(init, token::...)] requires `token::seeds = [...]` parameter. \
   912→                 Token accounts must be PDAs and need seeds for CPI signing.",
   913→            ));
   914→        }
   915→        if mint.is_none() {
   916→            return Err(Error::new_spanned(
   917→                attr,
   918→                "#[light_account(init, token::...)] requires `token::mint` parameter",
   919→            ));
   920→        }
   921→        if owner.is_none() {
   922→            return Err(Error::new_spanned(
   923→                attr,
   924→                "#[light_account(init, token::...)] requires `token::owner` parameter",
   925→            ));
   926→        }
   927→        // owner_seeds is required for init mode too (needed for decompression)
   928→        if !has_owner_seeds {
   929→            return Err(Error::new_spanned(
   930→                attr,
   931→                "#[light_account(init, token::...)] requires `token::owner_seeds = [...]` parameter \
   932→                 for decompression support. The token owner must be a PDA with constant seeds.",
   933→            ));
   934→        }
   935→    } else {
   936→        // Mark-only mode: requires seeds and owner_seeds, forbids mint and owner
   937→        if seeds.is_none() {
   938→            return Err(Error::new_spanned(
   939→                attr,
   940→                "#[light_account(token::...)] requires `token::seeds = [...]` parameter \
   941→                 for seed struct generation.",
   942→            ));
   943→        }
   944→        if !has_owner_seeds {
   945→            return Err(Error::new_spanned(
   946→                attr,
   947→                "#[light_account(token::...)] requires `token::owner_seeds = [...]` parameter \
   948→                 for decompression support. The token owner must be a PDA with constant seeds.",
   949→            ));
   950→        }
   951→        if mint.is_some() {
   952→            return Err(Error::new_spanned(
   953→                attr,
   954→                "`token::mint` is not allowed in mark-only mode (#[light_account(token::...)] without init). \
   955→                 Only `token::seeds` and `token::owner_seeds` are permitted. \
   956→                 Remove `token::mint` or add `init` keyword.",
   957→            ));
   958→        }
   959→        if owner.is_some() {
   960→            return Err(Error::new_spanned(
   961→                attr,
   962→                "`token::owner` is not allowed in mark-only mode (#[light_account(token::...)] without init). \
   963→                 Only `token::seeds` and `token::owner_seeds` are permitted. \
   964→                 Remove `token::owner` or add `init` keyword.",
   965→            ));
   966→        }
   967→    }
   968→
   969→    // Extract token account PDA seeds from the array expression (for signing)
   970→    let seeds_vec = if let Some(ref seeds_expr) = seeds {
   971→        let extracted = extract_array_elements(seeds_expr)?;
   972→        if has_init && extracted.is_empty() {
   973→            return Err(Error::new_spanned(
   974→                seeds_expr,
   975→                "Empty seeds `token::seeds = []` not allowed for token account initialization. \
   976→                 Token accounts must be PDAs and need at least one seed for CPI signing.",
   977→            ));
   978→        }
   979→        extracted
   980→    } else {
   981→        Vec::new()
   982→    };
   983→
   984→    Ok(TokenAccountField {
   985→        field_ident: field_ident.clone(),
   986→        has_init,
   987→        seeds: seeds_vec,
   988→        mint,
   989→        owner,
   990→        bump,
   991→    })
   992→}
   993→
   994→/// Build an AtaField from parsed namespaced key-value pairs.
   995→///
   996→/// Mapping from new syntax to internal fields:
   997→/// - `associated_token::authority` -> `owner` (renamed to match Anchor's ATA naming)
   998→/// - `associated_token::mint` -> `mint`
   999→/// - `associated_token::bump` -> `bump`
  1000→fn build_ata_field(
  1001→    field_ident: &Ident,
  1002→    key_values: &[NamespacedKeyValue],
  1003→    has_init: bool,
  1004→    attr: &syn::Attribute,
  1005→) -> Result<AtaField, syn::Error> {
  1006→    let mut owner: Option<Expr> = None; // from associated_token::authority
  1007→    let mut mint: Option<Expr> = None;
  1008→
  1009→    for kv in key_values {
  1010→        match kv.key.to_string().as_str() {
  1011→            "authority" => owner = Some(kv.value.clone()), // authority -> owner
  1012→            "mint" => mint = Some(kv.value.clone()),
  1013→            "bump" => {
  1014→                return Err(Error::new_spanned(
  1015→                    &kv.key,
  1016→                    "`associated_token::bump` is no longer supported. The bump is derived on-chain.",
  1017→                ));
  1018→            }
  1019→            other => {
  1020→                return Err(Error::new_spanned(
  1021→                    &kv.key,
  1022→                    format!(
  1023→                        "Unknown key `associated_token::{}`. Allowed: authority, mint",
  1024→                        other
  1025→                    ),
  1026→                ));
  1027→            }
  1028→        }
  1029→    }
  1030→
  1031→    // Validate required fields
  1032→    let owner = owner.ok_or_else(|| {
  1033→        Error::new_spanned(
  1034→            attr,
  1035→            "#[light_account([init,] associated_token, ...)] requires `associated_token::authority` parameter",
  1036→        )
  1037→    })?;
  1038→    let mint = mint.ok_or_else(|| {
  1039→        Error::new_spanned(
  1040→            attr,
  1041→            "#[light_account([init,] associated_token, ...)] requires `associated_token::mint` parameter",
  1042→        )
  1043→    })?;
  1044→
  1045→    Ok(AtaField {
  1046→        field_ident: field_ident.clone(),
  1047→        has_init,
  1048→        owner,
  1049→        mint,
  1050→    })
  1051→}
  1052→
  1053→/// Convert an expression to an identifier (for field references).
  1054→fn expr_to_ident(expr: &Expr, field_name: &str) -> Result<Ident, syn::Error> {
  1055→    match expr {
  1056→        Expr::Path(path) => path.path.get_ident().cloned().ok_or_else(|| {
  1057→            Error::new_spanned(expr, format!("`{field_name}` must be a simple identifier"))
  1058→        }),
  1059→        _ => Err(Error::new_spanned(
  1060→            expr,
  1061→            format!("`{field_name}` must be a simple identifier"),
  1062→        )),
  1063→    }
  1064→}
  1065→
  1066→/// Extract elements from an array expression.
  1067→fn extract_array_elements(expr: &Expr) -> Result<Vec<Expr>, syn::Error> {
  1068→    match expr {
  1069→        Expr::Array(arr) => Ok(arr.elems.iter().cloned().collect()),
  1070→        Expr::Reference(r) => extract_array_elements(&r.expr),
  1071→        _ => Err(Error::new_spanned(
  1072→            expr,
  1073→            "Expected array expression like `[b\"seed\", other.key()]`",
  1074→        )),
  1075→    }
  1076→}
  1077→
  1078→/// Validates TokenMetadata field requirements.
  1079→///
  1080→/// Rules:
  1081→/// 1. `name`, `symbol`, `uri` must all be defined together or none
  1082→/// 2. `update_authority` and `additional_metadata` require `name`, `symbol`, `uri`
  1083→fn validate_metadata_fields(
  1084→    name: &Option<Expr>,
  1085→    symbol: &Option<Expr>,
  1086→    uri: &Option<Expr>,
  1087→    update_authority: &Option<Ident>,
  1088→    additional_metadata: &Option<Expr>,
  1089→    attr: &syn::Attribute,
  1090→) -> Result<(), syn::Error> {
  1091→    let has_name = name.is_some();
  1092→    let has_symbol = symbol.is_some();
  1093→    let has_uri = uri.is_some();
  1094→    let has_update_authority = update_authority.is_some();
  1095→    let has_additional_metadata = additional_metadata.is_some();
  1096→
  1097→    let core_metadata_count = [has_name, has_symbol, has_uri]
  1098→        .iter()
  1099→        .filter(|&&x| x)
  1100→        .count();
  1101→
  1102→    // Rule 1: name, symbol, uri must all be defined together or none
  1103→    if core_metadata_count > 0 && core_metadata_count < 3 {
  1104→        return Err(Error::new_spanned(
  1105→            attr,
  1106→            "TokenMetadata requires all of `mint::name`, `mint::symbol`, and `mint::uri` to be specified together",
  1107→        ));
  1108→    }
  1109→
  1110→    // Rule 2: update_authority and additional_metadata require name, symbol, uri
  1111→    if (has_update_authority || has_additional_metadata) && core_metadata_count == 0 {
  1112→        return Err(Error::new_spanned(
  1113→            attr,
  1114→            "`mint::update_authority` and `mint::additional_metadata` require `mint::name`, `mint::symbol`, and `mint::uri` to also be specified",
  1115→        ));
  1116→    }
  1117→
  1118→    Ok(())
  1119→}
