  1127→    fn from(pda: PdaField) -> Self {
  1128→        Self {
  1129→            field_name: pda.ident,
  1130→            is_boxed: pda.is_boxed,
  1131→            is_zero_copy: pda.is_zero_copy,
  1132→            address_tree_info: Some(pda.address_tree_info),
  1133→            output_tree: Some(pda.output_tree),
  1134→        }
  1135→    }
  1136→}
